@OverflowThrowing
func add(a: Int8, b: Int8){
    return a + b
}
main() {
    add(100,29)
    /* 数学上 100 + 29 等于 129，
    * 在 Int8 的范围内发生上溢，
    * 导致抛出异常
    */
}

@OverflowWrapping
main() {
    let res: Int8 = Int8(105) * Int8(4)
    /* 数学上 105 * 4 等于 420，
    * 其二进制表示为 1 1010 0100，
    * 超出结果 8 位内存空间。
    * 截断后的结果用二进制表示为 1010 0100，
    * 对应有符号整数 -92
    */
}

@OverflowSaturating
main() {
    let res: Int8 = Int8(-100) - Int8(45)
    /* 数学上 -100 - 45 等于 -145，
    * 在 Int8 的范围内发生下溢，
    * 因此选择 Int8 的最小值 -128 作为结果
    */
}

